#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005
#define MAX_M 700
int maxJoy = 0;
int N, M1, M2;
int tree[MAX_N][MAX_N];
int btsRoutes[MAX_M][3];
int gtnRoutes[MAX_M][3];
void dfs(int node, int parent, int btsMask, int gtnMask, int currentJoy) {
    maxJoy = (maxJoy > currentJoy) ? maxJoy : currentJoy;
    for (int i = 0; i < M1; i++) {
        if ((btsMask & (1 << i)) == 0) {
            int start = btsRoutes[i][0];
            int end = btsRoutes[i][1];
            int joy = btsRoutes[i][2];
            if (start == node || end == node) {
                dfs(node, parent, btsMask | (1 << i), gtnMask, currentJoy + joy);
            }
        }
    }
    for (int i = 0; i < M2; i++) {
        if ((gtnMask & (1 << i)) == 0) {
            int start = gtnRoutes[i][0];
            int end = gtnRoutes[i][1];
            int joy = gtnRoutes[i][2];
            if (start == node || end == node) {
                dfs(node, parent, btsMask, gtnMask | (1 << i), currentJoy + joy);
            }
        }
    }
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        scanf("%d %d %d", &N, &M1, &M2);
        for (int i = 0; i < N - 1; i++) {
            int x, y;
            scanf("%d %d", &x, &y);
            tree[x][y] = tree[y][x] = 1;
        }
        for (int i = 0; i < M1; i++) {
            scanf("%d %d %d", &btsRoutes[i][0], &btsRoutes[i][1], &btsRoutes[i][2]);
        }
        for (int i = 0; i < M2; i++) {
            scanf("%d %d %d", &gtnRoutes[i][0], &gtnRoutes[i][1], &gtnRoutes[i][2]);
        }
        maxJoy = 0;
        dfs(1, -1, 0, 0, 0);
        printf("%d\n", maxJoy);
    }
    return 0;
}

