import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;
import java.util.StringTokenizer;
public class Main {
    static int maxJoy = 0;
    static int N, M1, M2;
    static int[][] tree;
    static int[][] btsRoutes;
    static int[][] gtnRoutes;
    public static void main(String[] args) throws IOException {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine());
        while (T-- > 0) {
            StringTokenizer st = new StringTokenizer(br.readLine());
            N = Integer.parseInt(st.nextToken());
            M1 = Integer.parseInt(st.nextToken());
            M2 = Integer.parseInt(st.nextToken());
            tree = new int[N + 1][N + 1];
            btsRoutes = new int[M1][3];
            gtnRoutes = new int[M2][3];
            for (int i = 0; i < N - 1; i++) {
                st = new StringTokenizer(br.readLine());
                int x = Integer.parseInt(st.nextToken());
                int y = Integer.parseInt(st.nextToken());
                tree[x][y] = tree[y][x] = 1;
            }
            for (int i = 0; i < M1; i++) {
                st = new StringTokenizer(br.readLine());
                btsRoutes[i][0] = Integer.parseInt(st.nextToken());
                btsRoutes[i][1] = Integer.parseInt(st.nextToken());
                btsRoutes[i][2] = Integer.parseInt(st.nextToken());
            }
            for (int i = 0; i < M2; i++) {
                st = new StringTokenizer(br.readLine());
                gtnRoutes[i][0] = Integer.parseInt(st.nextToken());
                gtnRoutes[i][1] = Integer.parseInt(st.nextToken());
