        maxJoy = Math.max(maxJoy, currentJoy);
        for (int i = 0; i < M1; i++) {
            if ((btsMask & (1 << i)) == 0) {
                int start = btsRoutes[i][0];
                int end = btsRoutes[i][1];
                int joy = btsRoutes[i][2];
                if (start == node || end == node) {
                    dfs(node, parent, btsMask | (1 << i), gtnMask, currentJoy + joy);
                }
            }
        }
        for (int i = 0; i < M2; i++) {
            if ((gtnMask & (1 << i)) == 0) {
                int start = gtnRoutes[i][0];
                int end = gtnRoutes[i][1];
                int joy = gtnRoutes[i][2];
                if (start == node || end == node) {
                    dfs(node, parent, btsMask, gtnMask | (1 << i), currentJoy + joy);
